module RefModule (
    input [7:0] data_in,
    input [3:0] expected_checksum,
    output reg valid
);
    integer obf_i;
    reg [3:0] computed_checksum;

    always @(*) begin
        computed_checksum = 4'b0000;
        for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin
            computed_checksum = computed_checksum + data_in[obf_i];
        end
        valid = (computed_checksum == expected_checksum);
    end
endmodule
